UPDATE public.global_master_list AS gml
SET
  street       = COALESCE(NULLIF(a.street, ''), gml.street),
  city         = COALESCE(NULLIF(a.city, ''), gml.city),
  province     = COALESCE(NULLIF(a.province, ''), gml.province),
  postal_code  = COALESCE(NULLIF(a.postal_code, ''), gml.postal_code),
  full_address = COALESCE(NULLIF(a.full_address, ''), gml.full_address)
FROM address_data AS a
WHERE LOWER(TRIM(gml."Work Email")) = LOWER(TRIM(a.work_email));

-- ============================================================================
-- Refresh the active_employees view so the new columns surface to the API.
-- Postgres expands SELECT * at view-creation time; adding columns to the
-- underlying table does NOT propagate until the view is recreated.
-- The /api/employees route (and EmployeeProfile) reads from this view.
-- ============================================================================
CREATE OR REPLACE VIEW public.active_employees AS
SELECT *
FROM public.global_master_list
WHERE last_seen_upload_id = (
  SELECT id FROM public.master_list_uploads WHERE is_current = TRUE LIMIT 1
);

-- Verify columns are visible in the view
SELECT column_name
FROM information_schema.columns
WHERE table_schema = 'public' AND table_name = 'active_employees'
  AND column_name IN ('street', 'city', 'province', 'postal_code', 'full_address')
ORDER BY column_name;

-- Verify backfill counts
SELECT
  COUNT(*) FILTER (WHERE full_address IS NOT NULL) AS with_full_address,
  COUNT(*) FILTER (WHERE street       IS NOT NULL) AS with_street,
  COUNT(*) FILTER (WHERE city         IS NOT NULL) AS with_city,
  COUNT(*) FILTER (WHERE province     IS NOT NULL) AS with_province,
  COUNT(*) FILTER (WHERE postal_code  IS NOT NULL) AS with_postal_code,
  COUNT(*)                                          AS total_rows
FROM public.global_master_list;
